const item = $input.first().json;
const message = String(item.message || '').trim();
const lower = message.toLowerCase();
const hints = { intent: 'general', category: '', needsRag: true, topK: 4 };
const categories = ['monitor','ssd','disco','ram','memoria','teclado','mouse','raton','gpu','tarjeta','cpu','procesador','laptop','portatil','fuente','case','gabinete'];
for (const c of categories) {
  if (lower.includes(c)) { hints.category = c; hints.intent = 'product_lookup'; break; }
}
if (/(precio|cuesta|valor|stock|disponible|cantidad|código|codigo)/i.test(message)) hints.intent = 'inventory_query';
const queryOptimized = message
  .replace(/\b(hola|buenas|por favor|please|gracias)\b/gi, '')
  .replace(/\s+/g, ' ')
  .trim();
return [{ json: { ...item, queryOriginal: message, queryOptimized: queryOptimized || message, retrievalHints: hints, trace: { queryOptimizedAt: new Date().toISOString(), hints } } }];

return $input.all().map(({ json }) => {
  const msg = String(json.message || '').toLowerCase();

  let complexityScore = 2;
  let routingReason = 'forced_chatgpt_default';

  // Clasificación de complejidad, pero SIN cambiar el modelo
  if (
    msg.length < 80 &&
    !/(compar|recomienda|alternativa|explica|compatib|rendimiento|gaming)/.test(msg)
  ) {
    complexityScore = 1;
    routingReason = 'simple_query_forced_to_chatgpt';
  }

  if (/(precio|stock|disponible|codigo|código|cantidad|cuesta|valor)/.test(msg)) {
    complexityScore = 2;
    routingReason = 'inventory_query_forced_to_chatgpt';
  }

  if (/(compar|recomienda|mejor|compatib|rendimiento|gaming|alternativa)/.test(msg)) {
    complexityScore = 4;
    routingReason = 'complex_query_forced_to_chatgpt';
  }

  if (/(informe|analiza|estrategia|arquitectura|diagnostica)/.test(msg)) {
    complexityScore = 5;
    routingReason = 'advanced_query_forced_to_chatgpt';
  }

  return {
    json: {
      ...json,

      // IMPORTANTE: forzamos siempre ChatGPT
      modelName: 'chatgpt',

      // Guardamos el modelo original por trazabilidad
      requestedModelName: json.modelName || null,

      complexityScore,
      routingReason,

      trace: {
        ...(typeof json.trace === 'object' ? json.trace : {}),
        modelRouter: {
          forcedModel: 'chatgpt',
          previousModel: json.modelName || null,
          complexityScore,
          routingReason,
          routedAt: new Date().toISOString()
        }
      }
    }
  };
});

return $input.all().map(({json}) => {
  const now = new Date().toISOString();
  const trace = {
    ...(typeof json.trace === 'object' ? json.trace : {}),
    completedAt: now,
    channel: json.channel,
    requestId: json.requestId,
    responseChars: String(json.output || '').length,
    optimization: 'TOON + dynamic chunking + topK4 + concise context'
  };
  return { json: { ...json, trace } };
});
